package com.vidaysalud.veterinaria.notificacionservicio.model;import jakarta.persistence.*;import lombok.*;import java.time.LocalDateTime;@Entity @Table(name="notificacion") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Notificacion{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)@Column(name="id_notificacion")private Integer idNotificacion;@Column(name="id_cliente",nullable=false)private Integer idCliente;@Enumerated(EnumType.STRING)@Column(nullable=false)private TipoNotificacion tipo;@Column(nullable=false,length=150)private String destinatario;@Column(nullable=false,length=150)private String asunto;@Lob @Column(nullable=false)private String mensaje;@Enumerated(EnumType.STRING)@Column(nullable=false)private EstadoNotificacion estado;@Column(name="fecha_creacion",nullable=false,updatable=false)private LocalDateTime fechaCreacion;@Column(name="fecha_envio")private LocalDateTime fechaEnvio;@PrePersist void pre(){if(estado==null)estado=EstadoNotificacion.PENDIENTE;if(fechaCreacion==null)fechaCreacion=LocalDateTime.now();}}